def get_pdf_text_from_gdrive(url):
    """Downloads the PDF from Google Drive and extracts its text."""
    file_id = extract_gdrive_id(url)
    if not file_id:
        return None, "Invalid Google Drive URL"

    # Direct download link for Google Drive
    download_url = f'https://drive.google.com/uc?export=download&id={file_id}'

    try:
        response = requests.get(download_url)
        response.raise_for_status()

        # Open PDF from memory (stream)
        with fitz.open(stream=response.content, filetype="pdf") as doc:
            text = ""
            # Extract first 15 pages to stay within Gemini context limits
            for page in doc[:15]: 
                text += page.get_text()
        return text, None
    except Exception as e:
        return None, str(e)
